import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it("returns 5 G premium for an empty item list (processing fee only)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      };
      const result = processScenario(scenario);
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it.todo("returns 105 G premium for a single sword (100 base + 5 fee)");
    it.todo("returns 65 G premium for a single amulet (60 base + 5 fee)");
    it.todo("returns 85 G premium for a single staff (80 base + 5 fee)");
    it.todo("returns 45 G premium for a single potion (40 base + 5 fee)");
    it.todo("returns 30 G premium for a single rune component (25 base + 5 fee)");
    it.todo("returns 165 G premium for a sword and an amulet (100 + 60 + 5 fee)");
  });

  describe("Quote - component block pricing", () => {
    it.todo("returns 55 G for 2 runes (2 * 25 = 50 + 5 fee)");
    it.todo("returns 65 G for 3 runes (block price 60 + 5 fee)");
    it.todo("returns 105 G for 4 runes (4 * 25 = 100 + 5 fee, no block)");
    it.todo("returns 80 G for 2 runes and 1 moonstone (no block, different types, 75 + 5 fee)");
    it.todo("returns 125 G for 3 runes and 3 moonstones (two blocks, 60 + 60 + 5 fee)");
  });

  describe("Quote - item-specific modifiers", () => {
    it.todo("adds 50% curse surcharge to a cursed sword (100 + 50 + 5 = 155 G)");
    it.todo("adds 30% high-enchantment surcharge for enchantment level 5 (100 + 30 + 5 = 135 G)");
    it.todo("applies both curse and high-enchantment surcharges (100 + 50 + 30 + 5 = 185 G)");
    it.todo("does not apply high-enchantment surcharge for enchantment level 4");
    it.todo("applies item-specific modifiers only to the affected item in a multi-item policy");
  });

  describe("Quote - policy-wide modifiers", () => {
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 10% first insurance surcharge (always applies per quote)");
    it.todo("applies 15% follow-up discount on each contract after the first");
    it.todo("applies loyalty discount to customer with exactly 2 years");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword: 0 years, first contract = 165 G");
    it.todo("long-standing customer second contract with cursed high-enchantment sword = 160 G");
    it.todo("rounds premium up in MHPCO's favor");
  });

  describe("Claim - basic payout", () => {
    it.todo("applies 100 G deductible to damage on a regular sword");
    it.todo("returns remaining cap after a claim");
    it.todo("fully reimburses dragon-material item minus deductible");
    it.todo("reimburses at 50% for enchantment >= 8, then applies deductible");
    it.todo("applies 50% rule when item is both dragon-material and enchantment >= 8");
  });

  describe("Claim - cap and multiple damages", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("applies deductible per damaged item in a single event");
    it.todo("tracks remaining cap across successive claims");
    it.todo("reduces payout to remaining cap when cap is nearly exhausted");
  });

  describe("Claim - payout rounding", () => {
    it.todo("rounds payout down in MHPCO's favor");
  });

  describe("Error handling", () => {
    it.todo("rejects unknown item type in a quote");
    it.todo("rejects claim damage for item not in policy");
    it.todo("rejects negative damage amount");
    it.todo("rejects more damages of a type than policy covers");
  });

  describe("CLI integration", () => {
    it.todo("reads scenario from stdin and writes results to stdout");
    it.todo("processes sequential quote and claim steps");
  });
});

