const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const calculateQuotePremium = (items: any[]): { premium: number } => {
  const basePremium = items.reduce(
    (sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] || 0),
    0
  );
  return { premium: basePremium + PROCESSING_FEE };
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => calculateQuotePremium(step.items));
  return { results };
};

