const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const COMPONENT_PREMIUM = 25;

const calculateQuotePremium = (items: any[]): { premium: number } => {
  const componentCounts: Record<string, number> = {};
  let basePremium = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      basePremium += BASE_PREMIUMS[item.type] || 0;
    }
  }

  for (const count of Object.values(componentCounts)) {
    if (count === BLOCK_SIZE) {
      basePremium += BLOCK_PREMIUM;
    } else {
      basePremium += count * COMPONENT_PREMIUM;
    }
  }

  return { premium: basePremium + PROCESSING_FEE };
};

