  for (const count of Object.values(componentCounts)) {
    if (count === BLOCK_SIZE) {
      itemsCost += BLOCK_PREMIUM;
    } else {
      itemsCost += count * COMPONENT_PREMIUM;
    }
  }

  return { premium: itemsCost + PROCESSING_FEE };
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => calculateQuotePremium(step.items));
  return { results };
};

