const COMPONENT_INSURANCE_VALUE = 250;

const calculateInsuranceSum = (items: any[]): number => {
  return items.reduce((sum, item) => {
    if (COMPONENT_TYPES.has(item.type)) {
      return sum + COMPONENT_INSURANCE_VALUE;
    }
    return sum + (INSURANCE_VALUES[item.type] || 0);
  }, 0);
};

const processClaim = (step: any, policies: any[]): { payout: number; remainingCap: number } => {
  const policy = policies[step.policy];
  const totalPayout = step.incident.damages.reduce((sum: number, damage: any) => {
    return sum + Math.max(0, damage.amount - DEDUCTIBLE);
  }, 0);
  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
  policy.remainingCap -= cappedPayout;
  return { payout: Math.floor(cappedPayout), remainingCap: policy.remainingCap };
};

export const processScenario = (scenario: any): any => {
  const policies: any[] = [];
  let quoteIndex = 0;
  const results = scenario.steps.map((step: any) => {
    if (step.op === "claim") {
      return processClaim(step, policies);
    }
    const result = calculateQuotePremium(step.items, scenario.customer, quoteIndex);
    policies.push({
      items: step.items,
      insuranceSum: calculateInsuranceSum(step.items),
      remainingCap: calculateInsuranceSum(step.items) * 2,
    });
    quoteIndex++;
    return result;
  });
  return { results };
};

